// If you call addClickListener multiple times without removing the old listeners, they pile up and can leak memory.

function addClickListener() {
  const button = document.getElementById('myButton');
  function handleClick() {
    console.log('Button clicked!');
  }
  button.addEventListener('click', handleClick);

  // Return a cleanup function to remove the listener when done
  return () => {
    button.removeEventListener('click', handleClick);
  };
}

const cleanup = addClickListener();
// Later in your code, call cleanup() to prevent leaks

